---@class LxVideo
local LxVideo = classX("LxVideo", nil)

local UnityEngine = UnityEngine
local RenderTexture = UnityEngine.RenderTexture
local RenderTextureFormat = UnityEngine.RenderTextureFormat
local FilterMode = UnityEngine.FilterMode
local TextureWrapMode = UnityEngine.TextureWrapMode

local Video = UnityEngine.Video
local VideoSource = Video.VideoSource
local VideoSourceType = {
    VideoClip = VideoSource.VideoClip,
    Url = VideoSource.Url
}

local VideoAspectRatio = Video.VideoAspectRatio
local VideoAspectRatioType = {
    Stretch = VideoAspectRatio.Stretch,
    FitInside = VideoAspectRatio.FitInside,
}

local VideoRenderMode = Video.VideoRenderMode
local RenderMode = {
    CameraNearPlane = VideoRenderMode.CameraNearPlane,
    RenderTexture = VideoRenderMode.RenderTexture,
}
local typeofAudioSource = typeof(UnityEngine.AudioSource)
local typeofVideoPlayer = typeof(Video.VideoPlayer)
local typeofVideoClip = typeof(Video.VideoClip)

local VideoStatus = {
    None = 0,
    LoadClip = 1,
    Prepare = 2,
    DelayPlay = 3,
    Playing = 4,
    Pause = 5,
    Stop = 6,
    Error = 7,
    Released = 8
}

local movieLayersMask = LayerMask.NameToLayer("Movie")

function LxVideo:LxVideo()
    self._status = 0
    self._releaseTime = 0
    self._delayPlayTime = 0

    ---@type LxResRequester
    self._resRequester = nil
end

function LxVideo:Initialize(id, camera, parentTrans)
    self._movieId = id
    self._movieCamera = camera
    self._parentTrans = parentTrans
    self._aspectRatio = VideoAspectRatioType.Stretch
end

function LxVideo:Dispose()
    self._isWaitRelease = nil
    self:StopPlay()
    self:ClearMovieRT()

    self:ClearResRequester()

    table.dispose(self)
    self._isDisposed = true
end

function LxVideo:ClearResRequester()
    if self._resRequester ~= nil then
        self._resRequester:Dispose()
        self._resRequester = nil
    end
end

function LxVideo:GetMoveId()
    return self._movieId
end

function LxVideo:IsPlaying()
    local videoPlayer = self._videoPlayer
    if not IsNull(videoPlayer) and videoPlayer.isPlaying then
        return true
    end
    return false
end

function LxVideo:IsDisposed()
    return self._isDisposed
end

function LxVideo:IsEnd()
    return self._status == VideoStatus.Released
end

function LxVideo:StopPlay(executeOk)
    if self._status == VideoStatus.Stop then return end
    self._status = VideoStatus.Stop
    if self._movieCamera then
        self._movieCamera.enabled = false
    end
    local videoPlayer = self._videoPlayer
    if IsNull(videoPlayer) then
        return
    end
    if videoPlayer.isPlaying then videoPlayer:Stop() end
    self:ClearMovieRT()
    self._stopOkCb = executeOk
    self._releaseTime = Time.unscaledTime + 1
    self:ClearVideoPlayer()
end

function LxVideo:OnUpdate()
    if self._isDisposed then return end
    if self._status == VideoStatus.DelayPlay and Time.time > self._delayPlayTime then
        self:InternalPlay()
    end
    if self._status == VideoStatus.Stop and Time.unscaledTime > self._releaseTime then
        self:ClearVideoPlayer()
    end
end

function LxVideo:Resume()
    local videoPlayer = self._videoPlayer
    if IsNull(videoPlayer) then return end
    if videoPlayer.isPaused then
        videoPlayer:Play()
        self._status = VideoStatus.Playing
    end
end

function LxVideo:Pause()
    local videoPlayer = self._videoPlayer
    if IsNull(videoPlayer) then return end
    if videoPlayer.isPlaying then
        videoPlayer:Pause()
        self._status = VideoStatus.Pause
    end
end

function LxVideo:Play(params)
    self:InitPlayer(params)
end

function LxVideo:InternalPlay()
    self._status = VideoStatus.Playing
    local videoPlayer = self._videoPlayer
    self._audioSource:Stop()
    if videoPlayer:IsAudioTrackEnabled(0) then
        videoPlayer:SetTargetAudioSource(0, self._audioSource)
    end
    if self._movieCamera then
        self._movieCamera.enabled = true
    end
    if self._rawImage then
        self._rawImage.enabled = true

        if self._isFitHor then
            local width = videoPlayer.width
            local height = videoPlayer.height
            local rect = self._rawImage.transform.rect
            local imgW = rect.width
            local imgH = math.floor(imgW * height / width)
            self._rawImage.transform.sizeDelta = Vector2(imgW, imgH)
        end
    end
    videoPlayer:Play()

    if self._videoBlackTrans and CS.IsValidObject(self._videoBlackTrans) then
        CS.ShowObject(self._videoBlackTrans, true)
        FireEvent(EventNames.VIDEO_SHOW_BLACK,true)
    end
end

function LxVideo:InitPlayer(params)
    self._playFinishedCb = params.executeOk
    self._movieName = params.url
    self._isFromFileUrl = params.isFileUrl
    self._videoSourceType = self._isFromFileUrl and VideoSourceType.Url or VideoSourceType.VideoClip
    self._rawImage = params.rawImage
    self._delayTime = params.delay or 0
    self._isDelay = self._delayTime > 0
    self._isLoop = params.loop and true or false
    self._isFitHor = params.fitHor
    self._videoBlackTrans = params.blackTrans

    if self._isFromFileUrl then
        self:LoadFile()
    else
        self:LoadClip()
    end
end

function LxVideo:LoadFile()
    --if not PJXUtil.IsFileExists(self._movieName) then
    --    self:OnErrorReceived(nil, "video file not exist in path="..tostring(self._movieName))
    --    return
    --end
    self._movieUrl = self:ValidUrl(self._movieName)
    self:PrepareVideo()
end


function LxVideo:ValidUrl(url)
    local isIgnore = false
    if CS.IsOSAndroid() then
        local apiLevel = LNativeHelper.GetCurrentApiVersion() or 0
        isIgnore = apiLevel >= 29
    elseif CS.IsOsWinOrEdit() then
        isIgnore = true
    elseif CS.IsOSOpenHarmony() then
        isIgnore = true
        --if string.startswith(url, "jar:") then
        --    isIgnore = true
        --end
    elseif CS.IsWebGL() then
        isIgnore = true
    end

    if isIgnore then return url end
    return "file://"..url
end

function LxVideo:LoadClip()
    self._status = VideoStatus.LoadClip
    local videoName = self._movieName

    local strList = string.split(videoName, '.')
    local fileName = strList[1] or videoName
    local langName = gLGameLanguage:GetAudioName(fileName)
    if not string.isempty(langName) then
        local fileExt = strList[2] or "mp4"
        videoName = string.format("%s.%s", langName, fileExt)
    end

    if string.isempty(videoName) then
        self:OnClipLoaded(nil)
        return
    end

    local assetPath = "Movie/" ..videoName

    --鸿蒙播放不了ab里的视频
    if CS.IsOSOpenHarmony() or CS.IsWebGL() then
        local bundlePath = "Assets/Res/"..assetPath
        local url = LxResUtil.GetBundlePath(bundlePath)
        self._movieName = url
        self._isFromFileUrl = true
        self._videoSourceType = VideoSourceType.Url
        if LOG_INFO_ENABLED then
            printInfo("video", "鸿蒙设备强制转成url播放， url : "..tostring(url) .. " assetPath : "..tostring(assetPath))
        end
        self:LoadFile()
        return
    end

    self:ClearResRequester()
    self._resRequester = LxResUtil.GetAssetRequester(assetPath, typeofVideoClip, function(obj)
        if self._status ~= VideoStatus.LoadClip then return end
        self:OnClipLoaded(obj)
    end)
    self._resRequester:StartRequester()
end

function LxVideo:OnClipLoaded(videoClip)
    if videoClip == nil then
        self:OnErrorReceived(nil , "video clip is nil")
        return
    end
    self._videoClip = videoClip
    self:PrepareVideo()
end

function LxVideo:PrepareVideo()
    self._status = VideoStatus.Prepare

    self:InitVideoPlayer()

    local videoPlayer = self._videoPlayer
    if self._isFromFileUrl then
        videoPlayer.source = VideoSourceType.Url
        videoPlayer.url = self._movieUrl
        if LOG_INFO_ENABLED then
            printInfo("video", "播放的Url ："..tostring(self._movieUrl))
        end
    else
        videoPlayer.source = VideoSourceType.VideoClip
        videoPlayer.clip = self._videoClip

    end

    if not videoPlayer.isPrepared then
        videoPlayer:Prepare()
    else
        self:OnPrepareCompleted()
    end
end

function LxVideo:ClearMovieRT()
    if not IsNull(self._rawImage) then
        self._rawImage.texture = nil
        self._rawImage = nil
    end
    if self._movieCamera ~= nil then
        self._movieCamera.targetTexture = nil
    end
    if self._videoPlayer ~= nil then
        self._videoPlayer.targetTexture = nil
    end

    if CS.IsValidObject(self._videoBlackTrans) then
        CS.ShowObject(self._videoBlackTrans,false)
        FireEvent(EventNames.VIDEO_SHOW_BLACK,false)
        self._videoBlackTrans = nil
    end

    if self._movieRT ~= nil then
        RenderTexture.ReleaseTemporary(self._movieRT)
        self._movieRT = nil
    end
end

function LxVideo:InitMovieRT()
    local width, height = 1024,1024
    --width, height, depthBuffer, format
    local rt = RenderTexture.GetTemporary(width, height, 24, RenderTextureFormat.ARGB4444)
    rt.name = "movie_texture"
    rt.autoGenerateMips = false
    rt.filterMode = FilterMode.Bilinear
    rt.wrapMode = TextureWrapMode.Clamp
    self._movieRT = rt
end

function LxVideo:ClearVideoPlayer()
    local videoPlayer = self._videoPlayer
    self._status = VideoStatus.Released
    if IsNull(videoPlayer) then return end
    self._videoPlayer.clip = nil
    LxResUtil.UnloadAsset(self._videoClip)
    LxResUtil.DestroyObject(self._videoGameObject)
    self._audioSource = nil
    self._videoPlayer = nil
    self._videoGameObject = nil
    self._videoClip = nil
    if self._stopOkCb ~= nil then
        local func = self._stopOkCb
        self._stopOkCb = nil
        func()
    end
end

function LxVideo:InitVideoPlayer()
    local videoGo = LxResUtil.NewGameObject(tostring(self._movieId))
    self._videoGameObject = videoGo
    videoGo.transform:SetParent(self._parentTrans, false)
    videoGo.layer = movieLayersMask

    local audioSource = videoGo:AddComponent(typeofAudioSource)
    audioSource.playOnAwake = false
    audioSource.loop = false
    self._audioSource = audioSource

    local videoPlayer = videoGo:AddComponent(typeofVideoPlayer)
    self._videoPlayer = videoPlayer
    videoPlayer.playOnAwake = false
    videoPlayer.isLooping = self._isLoop
    videoPlayer.waitForFirstFrame = true
    videoPlayer.audioOutputMode = Video.VideoAudioOutputMode.AudioSource
    videoPlayer.aspectRatio = VideoAspectRatioType.Stretch

    if self._movieCamera then
        videoPlayer.renderMode = RenderMode.CameraNearPlane
        videoPlayer.targetCamera = self._movieCamera
    else
        self:InitMovieRT()
        videoPlayer.renderMode = RenderMode.RenderTexture
        videoPlayer.targetTexture = self._movieRT
    end

    if self._rawImage then
        self._rawImage.texture = self._movieRT
        self._rawImage.enabled = false
    end

    videoPlayer.prepareCompleted = videoPlayer.prepareCompleted + function(...)
        self:OnPrepareCompleted(...)
    end
    videoPlayer.loopPointReached = videoPlayer.loopPointReached + function(...)
        self:OnLoopPointReached(...)
    end
    videoPlayer.errorReceived = videoPlayer.errorReceived + function(...)
        self:OnErrorReceived(...)
    end
end

function LxVideo:OnPrepareCompleted(...)
    if self._status ~= VideoStatus.Prepare then return end
    if self._delayTime > 0 then
        self._status = VideoStatus.DelayPlay
        self._delayPlayTime = self._delayTime + Time.time
        return
    end
    self:InternalPlay()
end

function LxVideo:OnLoopPointReached()
    if self._isLoop then return end

    local func = self._playFinishedCb
    self._playFinishedCb = nil
    self:StopPlay(func)
end

function LxVideo:OnErrorReceived(player, msg)
    if LOG_INFO_ENABLED then
        printInfo("Video", "video error : %s", msg)
    end
    local func = self._playFinishedCb
    self._playFinishedCb = nil
    self:StopPlay(func)
end

function LxVideo:IsReady()
    local videoPlayer = self._videoPlayer
    if not videoPlayer then return false end
    if not self._isFromFileUrl and not self._videoClip then return false end
end

function LxVideo:GetLength()
    if not self:IsReady() then return 0 end
    return self._videoPlayer.length
end

function LxVideo:GetTime()
    if not self:IsReady() then return 0 end
    return self._videoPlayer.time
end

function LxVideo:SetTime(time)
    if not self:IsReady() then return 0 end
    self._videoPlayer.time = time
    self._videoPlayer:Play()
end
return LxVideo